	parts := strings.Split(fullPath, string(filepath.Separator))
	depth := cfg.ProjectDepth
	if depth > len(parts) {
		depth = len(parts)
	}
	displayPath := strings.Join(parts[len(parts)-depth:], "/")
	return strings.Contains(strings.ToLower(displayPath), filter)
